={{
  (() => {
    const loopNode = $('Loop Over Items');

    const title = loopNode.item.json.title || "No Title";
    const sourceKey = loopNode.item.json.source_key || "unknown";
    const sourceName = loopNode.item.json.source_name || "unknown";
    const sourcePlatform = loopNode.item.json.source_platform || "unknown";
    const signalOrigin = loopNode.item.json.signal_origin || "unknown";

    const rawContent = $('Jina_Reader').item.json.data;
    const sourceNameLower = String(sourceName).toLowerCase();
    const signalOriginLower = String(signalOrigin).toLowerCase();

    const isHackerNews = sourceKey === 'hackernews_frontpage' || sourceNameLower.includes('hackernews');
    const isOfficialOrAcademic = signalOriginLower === 'official' || signalOriginLower === 'academic';

    const maxContentChars = isHackerNews ? 22000 : 42000;

    const content = rawContent
      ? rawContent
          .replace(/!\[.*?\]\(.*?\)/g, '')
          .replace(/\[([^\]]+)\]\(http.*?\)/g, '$1')
          .replace(/\\/g, '/')
          .slice(0, maxContentChars)
      : "CONTENT_UNAVAILABLE_FALLBACK_TO_TITLE";

    let profile = "MEDIA";
    let profileRules = [
      "- Focus on core facts: who did what, key product/release, measurable impact.",
      "- Prefer hard numbers (benchmark/adoption/revenue/cost/latency); if missing write \u672a\u62ab\u9732.",
      "- Keep tone objective and concise, avoid hype."
    ];

    if (isHackerNews) {
      profile = "COMMUNITY";
      profileRules = [
        "- Treat content as community discussion signal, not official announcement.",
        "- Summarize into compact structured insight: \u6838\u5fc3\u8bae\u9898 / \u6280\u672f\u5206\u6b67 / \u53ef\u884c\u65b9\u6848 (only if present).",
        "- Do NOT translate user-by-user comments; synthesize consensus and disagreements."
      ];
    } else if (isOfficialOrAcademic) {
      profile = "OFFICIAL_OR_ACADEMIC";
      profileRules = [
        "- Use conservative factual style, no marketing wording.",
        "- Sentiment default is Neutral.",
        "- Upgrade to Positive ONLY with explicit measurable evidence (benchmark delta, adoption/users, revenue/ARR, GA in production, cost reduction)."
      ];
    }

    const promptParts = [
      "Task: Analyze ONE tech item and return STRICT JSON only.",
      "",
      "SOURCE_CONTEXT:",
      "- source_key: " + sourceKey,
      "- source_name: " + sourceName,
      "- source_platform: " + sourcePlatform,
      "- signal_origin: " + signalOrigin,
      "- profile: " + profile,
      "",
      "OUTPUT_SCHEMA (exactly these keys):",
      "{\"translation\": \"...\", \"summary\": \"...\", \"sentiment\": \"Positive|Neutral|Negative\"}",
      "",
      "GLOBAL_RULES:",
      "- translation format: [Tag] Chinese Title",
      "- allowed tags: [AI], [\u5b89\u5168], [\u786c\u4ef6], [\u5f00\u53d1], [\u5546\u4e1a], [\u751f\u6001]",
      "- [\u5b89\u5168] only for concrete incidents: CVE/0day/exploit/breach/ransomware/fraud/privacy incident",
      "- summary must be Chinese, <= 200 Chinese chars, complete sentence",
      "- if content inaccessible/paywall/403/captcha/too short, set summary EXACTLY to: Analysis failed due to content access issues.",
      "- if summary is the failure flag, sentiment must be Neutral",
      "- return JSON only, no markdown, no extra keys",
      "",
      "PROFILE_RULES:",
      ...profileRules,
      "",
      "INPUT_HEADLINE:",
      title,
      "",
      "FULL_CONTENT_START",
      content,
      "FULL_CONTENT_END"
    ];

    const userPrompt = promptParts.join("\n");

    return JSON.stringify({
      model: "qwen3-max-2025-09-23",
      max_tokens: 900,
      messages: [
        {
          role: "system",
          content: "You are a senior tech intelligence analyst. Output strict valid JSON only with keys translation, summary, sentiment. Never output markdown or extra fields."
        },
        {
          role: "user",
          content: userPrompt
        }
      ],
      response_format: { type: "json_object" }
    });
  })()
}}

